277	        where T : Attribute
278	    {
279	        var attributeSymbol = compilationContext.Types.TryGet(typeof(T).FullName ?? "<unknown>");
280	        return attributeSymbol == null ? [] : GetAttributes(attributeSymbol, attributes);

