+
+    [Fact]
+    public void DeepCloneSameTypeWithCopyConstructorShouldRespectMapperConstructor()
+    {
+        var source = TestSourceBuilder.MapperWithBodyAndTypes(
+            """
+            [MapProperty(nameof(A.Value), nameof(A.Value), Use = nameof(MapValue))]
+            private partial A Map(A source);
+            [UserMapping(Default = false)]
+            private string MapValue(string value) => value;
+            """,
+            TestSourceBuilderOptions.WithDeepCloning,
+            """
+            class A
+            {
+                [MapperConstructor]
+                public A() {}
+                public A(A other) { Value = other.Value; }
+                public string Value { get; init; }
+            }
+            """
+        );
+
+        TestHelper
+            .GenerateMapper(source)
+            .Should()
+            .HaveSingleMethodBody(
+                """
+                var target = new global::A()
+                {
+                    Value = MapValue(source.Value),
+                };
+                return target;
+                """
+            );
+    }
+
+    [Fact]
+    public void DeepCloneRecordSameTypeShouldRespectMapperConstructor()
+    {
+        var source = TestSourceBuilder.MapperWithBodyAndTypes(
+            """
+            [MapProperty(nameof(A.Value), nameof(A.Value), Use = nameof(MapValue))]
+            private partial A Map(A source);
+            [UserMapping(Default = false)]
+            private string MapValue(string value) => value;
+            """,
+            TestSourceBuilderOptions.WithDeepCloning,
+            """
+            record A
+            {
+                [MapperConstructor]
+                public A() {}
+                public string Value { get; init; }
+            }
+            """
+        );
+
+        TestHelper
+            .GenerateMapper(source)
+            .Should()
+            .HaveSingleMethodBody(
+                """
+                var target = new global::A()
+                {
+                    Value = MapValue(source.Value),
+                };
+                return target;
+                """
+            );
+    }
